package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.validation.*;import org.slf4j.*;import java.sql.SQLException;import java.time.LocalTime;import java.util.*;
/** Enforces schedule ownership, doctor state, overlap prevention and auditing. */public class DoctorScheduleServiceImpl implements DoctorScheduleService{private static final Logger LOG=LoggerFactory.getLogger(DoctorScheduleServiceImpl.class);private final DoctorScheduleDao schedules;private final DoctorDao doctors;private final DoctorScheduleValidator validator;private final AuditLogDao audit;public DoctorScheduleServiceImpl(){this(new DoctorScheduleDaoImpl(),new DoctorDaoImpl(),new DoctorScheduleValidator(),new AuditLogDaoImpl());}public DoctorScheduleServiceImpl(DoctorScheduleDao s,DoctorDao d,DoctorScheduleValidator v,AuditLogDao a){schedules=s;doctors=d;validator=v;audit=a;}public Page<DoctorSchedule> listSchedules(PageRequest r,Long d,Long dep,String day,Boolean av){PageRequest q=r==null?new PageRequest(1,10,""):r;try{return schedules.findAll(q,d,dep,day,av);}catch(Exception e){LOG.error("Schedule listing failed",e);return new Page<>(List.of(),q.getPageNumber(),q.getPageSize(),0);}}public Optional<DoctorSchedule> getSchedule(Long id){try{return id==null?Optional.empty():schedules.findById(id);}catch(SQLException e){LOG.error("Schedule lookup failed",e);return Optional.empty();}}public Optional<Doctor> getOwnDoctor(AuthenticatedUser u){try{return u==null?Optional.empty():doctors.findByUserId(u.getUserId());}catch(SQLException e){LOG.error("Doctor identity lookup failed",e);return Optional.empty();}}public List<Doctor> getActiveDoctors(){try{return doctors.findActiveDoctors();}catch(SQLException e){return List.of();}}public boolean canAccess(DoctorSchedule s,AuthenticatedUser u){if(u==null)return false;if("ADMIN".equals(u.getRoleName()))return true;if(!"DOCTOR".equals(u.getRoleName()))return false;return getOwnDoctor(u).map(d->d.getDoctorId().equals(s.getDoctorId())).orElse(false);}
 public ServiceResult<Long> createSchedule(DoctorScheduleForm f,AuditContext a,AuthenticatedUser u){normalize(f);ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Please correct the highlighted fields",v.getErrors());try{Long target=authorizedTarget(f.getDoctorId(),u,a,null);if(target==null)return forbidden();f.setDoctorId(target);Doctor d=doctors.findById(target).orElse(null);if(d==null)return fail(ServiceResult.Status.NOT_FOUND,"Doctor not found");if(!"ACTIVE".equals(d.getStatus())||!"ACTIVE".equals(d.getUserStatus()))return fail(ServiceResult.Status.CONFLICT,"Doctor account must be active");DoctorSchedule s=map(f);if(schedules.existsOverlap(target,s.getDayOfWeek(),s.getStartTime(),s.getEndTime())){event("DOCTOR_SCHEDULE_OVERLAP_BLOCKED",null,a);return fail(ServiceResult.Status.CONFLICT,"Schedule overlaps an existing window");}long id=schedules.create(s);event("DOCTOR_SCHEDULE_CREATED",id,a);return ServiceResult.success("Schedule created",id);}catch(SQLException e){LOG.error("Schedule creation failed",e);return system();}}
 public ServiceResult<Void> updateSchedule(DoctorScheduleForm f,AuditContext a,AuthenticatedUser u){if(f==null||f.getScheduleId()==null)return failv(ServiceResult.Status.NOT_FOUND,"Schedule not found");try{DoctorSchedule old=schedules.findById(f.getScheduleId()).orElse(null);if(old==null)return failv(ServiceResult.Status.NOT_FOUND,"Schedule not found");if(!canAccess(old,u)){event("DOCTOR_SCHEDULE_ACCESS_DENIED",f.getScheduleId(),a);return forbiddenv();}normalize(f);if("DOCTOR".equals(u.getRoleName()))f.setDoctorId(old.getDoctorId());ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Please correct the highlighted fields",v.getErrors());Doctor d=doctors.findById(f.getDoctorId()).orElse(null);if(d==null)return failv(ServiceResult.Status.NOT_FOUND,"Doctor not found");if(!"ACTIVE".equals(d.getStatus())||!"ACTIVE".equals(d.getUserStatus()))return failv(ServiceResult.Status.CONFLICT,"Doctor account must be active");DoctorSchedule s=map(f);s.setScheduleId(f.getScheduleId());if(schedules.existsOverlapExcludingId(s.getDoctorId(),s.getDayOfWeek(),s.getStartTime(),s.getEndTime(),s.getScheduleId())){event("DOCTOR_SCHEDULE_OVERLAP_BLOCKED",s.getScheduleId(),a);return failv(ServiceResult.Status.CONFLICT,"Schedule overlaps an existing window");}schedules.update(s);event("DOCTOR_SCHEDULE_UPDATED",s.getScheduleId(),a);return ServiceResult.success("Schedule updated",null);}catch(SQLException e){LOG.error("Schedule update failed",e);return systemv();}}
 public ServiceResult<Void> activateSchedule(Long id,AuditContext a,AuthenticatedUser u){return availability(id,true,a,u);}public ServiceResult<Void> deactivateSchedule(Long id,AuditContext a,AuthenticatedUser u){return availability(id,false,a,u);}private ServiceResult<Void> availability(Long id,boolean on,AuditContext a,AuthenticatedUser u){try{DoctorSchedule s=schedules.findById(id).orElse(null);if(s==null)return failv(ServiceResult.Status.NOT_FOUND,"Schedule not found");if(!canAccess(s,u)){event("DOCTOR_SCHEDULE_ACCESS_DENIED",id,a);return forbiddenv();}if(on){Doctor d=doctors.findById(s.getDoctorId()).orElse(null);if(d==null||!"ACTIVE".equals(d.getStatus())||!"ACTIVE".equals(d.getUserStatus()))return failv(ServiceResult.Status.CONFLICT,"Doctor account must be active");if(schedules.existsOverlapExcludingId(s.getDoctorId(),s.getDayOfWeek(),s.getStartTime(),s.getEndTime(),id)){event("DOCTOR_SCHEDULE_OVERLAP_BLOCKED",id,a);return failv(ServiceResult.Status.CONFLICT,"Schedule overlaps an existing window");}}schedules.updateAvailability(id,on);event(on?"DOCTOR_SCHEDULE_ACTIVATED":"DOCTOR_SCHEDULE_DEACTIVATED",id,a);return ServiceResult.success("Schedule availability updated",null);}catch(SQLException e){LOG.error("Schedule availability failed",e);return systemv();}}public List<DoctorSchedule> getAvailableSchedules(Long d,String day){try{return schedules.findAvailableByDoctorAndDay(d,day);}catch(SQLException e){return List.of();}}
 private Long authorizedTarget(Long submitted,AuthenticatedUser u,AuditContext a,Long id){if(u==null)return null;if("ADMIN".equals(u.getRoleName()))return submitted;if("DOCTOR".equals(u.getRoleName())){Optional<Doctor>d=getOwnDoctor(u);if(d.isPresent()&&d.get().getDoctorId().equals(submitted))return submitted;}event("DOCTOR_SCHEDULE_ACCESS_DENIED",id,a);return null;}private void normalize(DoctorScheduleForm f){if(f==null)return;f.setDayOfWeek(f.getDayOfWeek()==null?null:f.getDayOfWeek().trim().toUpperCase());f.setStartTime(f.getStartTime()==null?null:f.getStartTime().trim());f.setEndTime(f.getEndTime()==null?null:f.getEndTime().trim());f.setSlotDurationMinutes(f.getSlotDurationMinutes()==null?null:f.getSlotDurationMinutes().trim());}private DoctorSchedule map(DoctorScheduleForm f){DoctorSchedule s=new DoctorSchedule();s.setDoctorId(f.getDoctorId());s.setDayOfWeek(f.getDayOfWeek());s.setStartTime(LocalTime.parse(f.getStartTime()));s.setEndTime(LocalTime.parse(f.getEndTime()));s.setSlotDurationMinutes(Integer.parseInt(f.getSlotDurationMinutes()));s.setAvailable(f.isAvailable());return s;}private void event(String e,Long id,AuditContext a){try{AuditContext x=a==null?new AuditContext(null,null,null):a;audit.recordEvent(e,x.userId(),"DOCTOR_SCHEDULE",id,x.ipAddress(),x.userAgent());}catch(RuntimeException ex){LOG.warn("Schedule audit failed: {}",e,ex);}}private<T>ServiceResult<T>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Void>failv(ServiceResult.Status s,String m){return fail(s,m);}private ServiceResult<Long>forbidden(){return fail(ServiceResult.Status.FORBIDDEN,"Schedule access denied");}private ServiceResult<Void>forbiddenv(){return fail(ServiceResult.Status.FORBIDDEN,"Schedule access denied");}private ServiceResult<Long>system(){return fail(ServiceResult.Status.SYSTEM_ERROR,"Schedule service is temporarily unavailable");}private ServiceResult<Void>systemv(){return fail(ServiceResult.Status.SYSTEM_ERROR,"Schedule service is temporarily unavailable");}}
